// Extract message from WhatsApp Cloud API webhook payload
const body = $input.first().json.body || $input.first().json;

let senderPhone = '';
let messageText = '';
let messageType = 'text';
let senderName = '';

// WhatsApp Cloud API format
if (body.entry) {
  const entry = body.entry[0];
  const changes = entry.changes[0];
  const value = changes.value;

  // Skip status updates (only process messages)
  if (!value.messages || !value.messages[0]) {
    return []; // Empty = stop execution
  }

  const msg = value.messages[0];
  senderPhone = msg.from;
  messageText = msg.text?.body || msg.interactive?.button_reply?.title || msg.interactive?.list_reply?.title || '';
  messageType = msg.type;

  if (value.contacts && value.contacts[0]) {
    senderName = value.contacts[0].profile?.name || '';
  }
}
// Fallback
else if (body.from) {
  senderPhone = body.from;
  messageText = body.text?.body || body.body || '';
  senderName = body.profile_name || '';
}

// Normalize phone (remove + prefix)
senderPhone = senderPhone.replace(/^\+/, '');

if (!senderPhone || !messageText) {
  return []; // Stop if no valid message
}

return {
  json: {
    senderPhone,
    messageText: messageText.trim(),
    messageType,
    senderName: senderName || 'Customer',
    timestamp: new Date().toISOString()
  }
};

